717	\section{Global-sections evaluation isomorphism (iter-045)}
718	\label{sec:gammaObj_linearEquiv_top}
719	
720	Iter-044 landed the algebraic input \lstinline{Module.Finite k (Γ(C.left, ⊤))} from \lstinline{[IsIntegral C.left] [IsProper C.hom]} via Mathlib's \lstinline{finite_appTop_of_universallyClosed}. Iter-045 takes the next building-block step in the producer-instance assembly: lifting Mathlib's natural iso $\Gamma_{\Sheaf}(F) \cong F.\mathtt{obj}.\mathtt{obj}\,(\op\top)$ on a site with terminal $\top$ to a \lstinline{LinearEquiv} (the underlying iso is \emph{categorical} in $\ModuleCat\,k$, hence transports to a $k$-LinearEquiv between the carriers).
721	
722	Mathlib provides \lstinline{Sheaf.ΓNatIsoSheafSections} (\lstinline{Mathlib/CategoryTheory/Sites/GlobalSections.lean}): on a site $J$ with terminal $T$, the global-sections functor $\mathtt{Sheaf.\Gamma}\,J\,A \cong (\mathtt{sheafSections}\,J\,A).\mathtt{obj}\,(\op T)$. For the topology of opens $\mathtt{Opens.grothendieckTopology}\,X$, the terminal is the top open $\top$ (this is \lstinline{Preorder.isTerminalTop} for any preorder with a top element). Specialising the natural iso to a fixed sheaf $F$ via \lstinline{NatIso.app} and converting the resulting categorical iso in $\ModuleCat\,k$ via \lstinline{Iso.toLinearEquiv} gives the desired $\LinearEquiv$.
723	
724	Combining with iter-044's \lstinline{module_finite_globalSections_of_isProper} via \lstinline{Module.Finite.equiv} (using the \lstinline{.symm} orientation: source \lstinline{Γ(C.left, ⊤)}, target $(\Sheaf.\Gamma).\mathtt{obj}\,(\toModuleKSheaf\,C)$) yields $\Module.\mathrm{Finite}\,k$ on the global-sections object as a $\ModuleCat\,k$.
725	
726	\begin{theorem}\leanok
727	[Global-sections-to-top LinearEquiv]
728	  \label{thm:Scheme_SheafGammaObj_linearEquiv_top}
729	  \lean{AlgebraicGeometry.Scheme.SheafGammaObj_linearEquiv_top}
730	  \uses{def:Scheme_toModuleKSheaf}
731	  Let $k$ be a field, $X$ a topological space, and $F : \Sheaf\,(\opens.\mathtt{grothendieckTopology}\,X)\,(\ModuleCat\,k)$. Then there is a $k$-LinearEquiv
732	  \[
733	    (\Sheaf.\Gamma\,(\opens.\mathtt{grothendieckTopology}\,X)\,(\ModuleCat\,k)).\mathtt{obj}\,F \;\equivl{k}\; F.\mathtt{obj}.\mathtt{obj}\,(\op \top).
734	  \]
735	\end{theorem}
736	
737	\begin{proof}
738	  \leanok
739	  Apply \lstinline{Sheaf.ΓNatIsoSheafSections} with the terminal data $T := \top$ and $\hT := \mathtt{Preorder.isTerminalTop}\,\_$ to get the natural iso $\mathtt{Sheaf.\Gamma}\,J\,A \cong (\mathtt{sheafSections}\,J\,A).\mathtt{obj}\,(\op\top)$ in the functor category. Take the value at the fixed sheaf $F$ via \lstinline{NatIso.app}, obtaining a categorical iso in $\ModuleCat\,k$ between $(\Sheaf.\Gamma).\mathtt{obj}\,F$ and $((\mathtt{sheafSections}\,J\,A).\mathtt{obj}\,(\op\top)).\mathtt{obj}\,F = F.\mathtt{obj}.\mathtt{obj}\,(\op\top)$. Convert the categorical iso to a $\LinearEquiv\,k$ via \lstinline{Iso.toLinearEquiv}.
740	\end{proof}
741	
742	\begin{theorem}\leanok
743	[$\Module.\mathrm{Finite}\,k$ on $\Sheaf.\Gamma$-applied curve]
744	  \label{thm:Scheme_module_finite_gammaObj_of_isProper}
745	  \lean{AlgebraicGeometry.Scheme.module_finite_gammaObj_of_isProper}
746	  \uses{thm:Scheme_module_finite_globalSections_of_isProper, thm:Scheme_SheafGammaObj_linearEquiv_top, def:Scheme_toModuleKSheaf}
747	  Let $k$ be a field and $C : \Over\,(\Spec\,(\CommRingCat.\mathrm{of}\,k))$ with $\IsIntegral\,C.\mathtt{left}$ and $\IsProper\,C.\mathtt{hom}$. Then
748	  \[
749	    \Module.\mathrm{Finite}\,k\,((\Sheaf.\Gamma\,(\opens.\mathtt{grothendieckTopology}\,C.\mathtt{left}.\mathtt{toTopCat})\,(\ModuleCat\,k)).\mathtt{obj}\,(\toModuleKSheaf\,C)).
750	  \]
751	\end{theorem}
752	
753	\begin{proof}
754	  \uses{thm:Scheme_module_finite_globalSections_of_isProper, thm:Scheme_SheafGammaObj_linearEquiv_top}
755	  \leanok
756	  Apply Theorem~\ref{thm:Scheme_module_finite_globalSections_of_isProper} to extract $\Module.\mathrm{Finite}\,k\,(C.\mathtt{left}.\mathtt{presheaf}.\mathtt{obj}\,(\op\top))$. The carrier of $(\toModuleKSheaf\,C).\mathtt{obj}.\mathtt{obj}\,(\op\top)$ is definitionally $C.\mathtt{left}.\mathtt{presheaf}.\mathtt{obj}\,(\op\top)$ (via the iter-006 \lstinline{toModuleKPresheaf_obj} simp lemma), so $\Module.\mathrm{Finite}\,k$ holds on the carrier as a $\ModuleCat\,k$ via \lstinline{haveI}. Conclude by transporting via $\Module.\mathrm{Finite}.\mathtt{equiv}$ along the \lstinline{.symm} of Theorem~\ref{thm:Scheme_SheafGammaObj_linearEquiv_top}.
757	\end{proof}
